mapper.insert:
           INSERT INTO TB_SYS_INFO
           (
             SYS_CD
            ,P_SYS_CD			
            ,SYS_TP
            ,SYS_NM		
            ,SYS_DS_LST		
            ,SYS_DESC	
            ,CRET_DT			
            ,CRET_USER_ID	
           )
           VALUES
           (
             #{sysCd}
            ,#{parentSysCd}
            ,#{sysTp}
            ,#{sysNm}
			      ,#{sysDsLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
            ,#{sysDesc, jdbcType=VARCHAR}
            ,to_char(now(), 'YYYYMMDDHH24MISS')
            ,#{cretUserId, jdbcType=VARCHAR}
           )
           ON CONFLICT (SYS_CD) DO UPDATE
            SET
               P_SYS_CD = #{parentSysCd}
              ,SYS_TP = #{sysTp}
              ,SYS_NM = #{sysNm}
              ,SYS_DS_LST = #{sysDsLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
              ,SYS_DESC = #{sysDesc, jdbcType=VARCHAR}
              ,UPDT_DT = to_char(now(), 'YYYYMMDDHH24MISS')
              ,UPDT_USER_ID = #{updtUserId}

mapper.update:
UPDATE
  TB_SYS_INFO
SET
   P_SYS_CD = #{parentSysCd}
  ,SYS_TP = #{sysTp}
  ,SYS_NM = #{sysNm}
  ,SYS_DS_LST = #{sysDsLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
  ,SYS_DESC = #{sysDesc, jdbcType=VARCHAR}
  ,UPDT_DT = to_char(now(), 'YYYYMMDDHH24MISS')
  ,UPDT_USER_ID = #{updtUserId}
WHERE
  SYS_CD = #{sysCd}

mapper.delete:
DELETE FROM TB_SYS_INFO
WHERE
  SYS_CD IN

    #{item.sysCd}

  OR P_SYS_CD IN

    #{item.sysCd}

with recursive CODE_LIST(SYS_CD, P_SYS_CD, SYS_TP, SYS_NM, SYS_DS_LST, SYS_DESC, DEPTH, PATH, CYCLE) as ( select A.SYS_CD, A.P_SYS_CD, A.SYS_TP, A.SYS_NM, A.SYS_DS_LST, A.SYS_DESC, 1, array[A.SYS_NM::text], false from TB_SYS_INFO A where A.SYS_CD IN
#{item.sysCd}
union all select A.SYS_CD, A.P_SYS_CD, A.SYS_TP, A.SYS_NM, A.SYS_DS_LST, A.SYS_DESC, B.DEPTH + 1, array_append(B.PATH,A.SYS_NM::text), A.SYS_CD = any(B.PATH) from TB_SYS_INFO A, CODE_LIST B where A.P_SYS_CD = B.SYS_CD and not CYCLE ) DELETE FROM TB_SYS_INFO WHERE SYS_CD IN (SELECT SYS_CD FROM CODE_LIST)

