INSERT INTO ndata.tb_data_source
(
  DS_ID
 ,DSN
 ,DS_TP
 ,DBMS_TP
 ,DRIVER_NM
 ,SVR_ADDR
 ,PORT
 ,USER_ID
 ,PWD
 ,CHARSET
 ,PRIVATE_KEY
 ,DB_NAME
 ,RM_DIR
 ,CONN_PROPS
 ,SECURE_YN
)
VALUES
(
  #{id}
 ,#{dsn}
 ,#{dsTp, jdbcType=SMALLINT}
 ,#{dbmsTp, jdbcType=VARCHAR}
 ,#{driverName, jdbcType=VARCHAR}
 ,#{svrAddr}
 ,#{port}
 ,#{userId, jdbcType=VARCHAR}
 ,#{pwd, jdbcType=VARCHAR}
 ,#{charSet, jdbcType=VARCHAR}
 ,#{privateKey, jdbcType=VARCHAR}
 ,#{dbName, jdbcType=VARCHAR}
 ,#{rmDir, jdbcType=VARCHAR}
 ,#{connProps, jdbcType=VARCHAR}
 ,#{useSecure, jdbcType=BOOLEAN}
)

mapper.update:
UPDATE
  ndata.tb_data_source
SET
    DSN = #{dsn}
   ,DS_TP = #{dsTp}
   ,DBMS_TP = #{dbmsTp}
   ,DRIVER_NM = #{driverName}
   ,SVR_ADDR = #{svrAddr}
   ,PORT = #{port}
   ,USER_ID = #{userId}
   ,PWD = #{pwd}
   ,CHARSET = #{charSet}
   ,PRIVATE_KEY = #{privateKey}
   ,DB_NAME = #{dbName}
   ,RM_DIR = #{rmDir}
   ,CONN_PROPS = #{connProps}
   ,SECURE_YN = #{useSecure}
WHERE
  DS_ID = #{id}
